#!/usr/bin/env bash
set -euo pipefail

if [[ "${EUID}" -ne 0 ]]; then
  echo "Run as root: sudo $0" >&2
  exit 1
fi

APP_DIR="/opt/fmrec"
VENV="$APP_DIR/venv"
DATA_DIR="/var/lib/fmrec"
LOG_DIR="/var/log/fmrec"
ETC_DIR="/etc/fmrec"
TMP_ZIP="/tmp/fmrec_app_bundle_v3.zip"

echo "[1/10] Installing apt dependencies..."
apt-get update
DEBIAN_FRONTEND=noninteractive apt-get install -y   rtl-sdr ffmpeg   python3 python3-venv python3-pip   ca-certificates curl   logrotate unzip sudo   > /dev/null

echo "[2/10] Creating user and directories..."
id -u fmrec >/dev/null 2>&1 || useradd --system --home /nonexistent --no-create-home --shell /usr/sbin/nologin fmrec
usermod -a -G plugdev fmrec || true
mkdir -p "$APP_DIR" "$DATA_DIR/recordings" "$DATA_DIR/tmp" "$LOG_DIR" "$ETC_DIR"
chown -R fmrec:fmrec "$DATA_DIR" "$LOG_DIR"

echo "[3/10] Udev rules for RTL-SDR (permissions)..."
cat >/etc/udev/rules.d/20-rtl-sdr.rules <<'RULES'
SUBSYSTEMS=="usb", ATTRS{idVendor}=="0bda", ATTRS{idProduct}=="2838", MODE:="0666"
SUBSYSTEMS=="usb", ATTRS{idVendor}=="0bda", ATTRS{idProduct}=="2832", MODE:="0666"
RULES
udevadm control --reload-rules || true
udevadm trigger || true

echo "[4/10] Blacklisting DVB driver (recommended)..."
cat >/etc/modprobe.d/rtl-sdr-blacklist.conf <<'BL'
blacklist dvb_usb_rtl28xxu
blacklist rtl2832
blacklist rtl2830
BL
modprobe -r dvb_usb_rtl28xxu rtl2832 rtl2830 2>/dev/null || true

echo "[5/10] Setting up Python venv..."
if [[ ! -d "$VENV" ]]; then
  python3 -m venv "$VENV"
fi
"$VENV/bin/pip" install --upgrade pip wheel >/dev/null
"$VENV/bin/pip" install flask gunicorn requests beautifulsoup4 >/dev/null

echo "[6/10] Installing application files (embedded bundle)..."
rm -rf "$APP_DIR/app"
mkdir -p "$APP_DIR"
cat >"$TMP_ZIP.b64" <<'B64'

B64
base64 -d "$TMP_ZIP.b64" > "$TMP_ZIP"
rm -f "$TMP_ZIP.b64"
unzip -q -o "$TMP_ZIP" -d "$APP_DIR"
rm -f "$TMP_ZIP"
chown -R root:root "$APP_DIR/app"
chmod -R a+rX "$APP_DIR/app"

echo "[7/10] Sudoers (allow UI to set time & restart scheduler)..."
cat >/etc/sudoers.d/fmrec-time <<'SUDO'
Defaults:fmrec !requiretty
fmrec ALL=(root) NOPASSWD: /usr/bin/timedatectl set-time *, /usr/bin/timedatectl set-timezone *, /usr/bin/timedatectl set-ntp *, /usr/bin/systemctl restart fmrec-scheduler
SUDO
chmod 440 /etc/sudoers.d/fmrec-time

echo "[8/10] Creating systemd services..."
cat >/etc/systemd/system/fmrec-web.service <<'SVC'
[Unit]
Description=FMREC Web UI (Flask/Gunicorn)
After=network.target

[Service]
Type=simple
User=fmrec
Group=fmrec
Environment=FMREC_DB=/var/lib/fmrec/fmrec.db
Environment=FMREC_LOCK=/var/lock/fmrec_sdr.lock
WorkingDirectory=/opt/fmrec/app
ExecStart=/opt/fmrec/venv/bin/gunicorn --workers 1 --threads 8 --bind 0.0.0.0:8080 webapp:app
Restart=always
RestartSec=3

[Install]
WantedBy=multi-user.target
SVC

cat >/etc/systemd/system/fmrec-scheduler.service <<'SVC'
[Unit]
Description=FMREC Scheduler (runs recordings)
After=network.target

[Service]
Type=simple
User=fmrec
Group=fmrec
Environment=FMREC_DB=/var/lib/fmrec/fmrec.db
Environment=FMREC_LOCK=/var/lock/fmrec_sdr.lock
Environment=FMREC_PY=/opt/fmrec/venv/bin/python
Environment=FMREC_RECORD=/opt/fmrec/app/record.py
WorkingDirectory=/opt/fmrec/app
ExecStart=/opt/fmrec/venv/bin/python /opt/fmrec/app/scheduler.py
Restart=always
RestartSec=3

[Install]
WantedBy=multi-user.target
SVC

cat >/etc/logrotate.d/fmrec <<'LR'
/var/log/fmrec/*.log {
  weekly
  rotate 8
  compress
  missingok
  notifempty
  copytruncate
}
LR

echo "[9/10] Permissions & first-run init..."
touch /var/log/fmrec/fmrec.log || true
chown -R fmrec:fmrec "$DATA_DIR" "$LOG_DIR"
mkdir -p /var/lock
touch /var/lock/fmrec_sdr.lock
chown fmrec:fmrec /var/lock/fmrec_sdr.lock

echo "[10/10] Enabling services + quick self-check..."
systemctl daemon-reload
systemctl enable --now fmrec-web fmrec-scheduler

if command -v rtl_test >/dev/null 2>&1; then
  rtl_test -t >/dev/null 2>&1 || true
fi

echo
echo "✅ نصب/آپدیت شد (v3)."
echo "اگر RTL-SDR با rtl_test کار نکرد، یکبار Reboot کن (به خاطر blacklist ماژول DVB)."
echo "IP دستگاه را بگیر:  hostname -I"
echo "وب UI:  http://<IP-PI>:8080"
echo "لاگ‌ها: journalctl -u fmrec-web -u fmrec-scheduler -f"
